cell("code","def euler_method(f, x0, y0, dx, num_steps):\n    '''Approximate the solution to dy/dx = f(x,y) starting at (x0, y0).'''\n    xs, ys = [x0], [y0]\n    # YOUR CODE HERE\n    return xs, ys\n\n# Test with dy/dx = y (Exponential growth), starting at (0, 1)\n# xs, ys = euler_method(lambda x, y: y, 0, 1, 0.1, 10)\n# assert abs(ys[-1] - 2.5937) < 1e-2  # Approx e^1\n# print('Step 2 passed ✅')"),
